-- Create "alert_source_profiles" table
CREATE TABLE "alert_source_profiles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "kind" character varying NOT NULL,
  "base_url" character varying NOT NULL,
  "auth_mode" character varying NOT NULL DEFAULT 'none',
  "secret_ref" character varying NULL,
  "enabled" boolean NOT NULL DEFAULT false,
  "labels" jsonb NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "alert_source_profiles_name_key" to table: "alert_source_profiles"
CREATE UNIQUE INDEX "alert_source_profiles_name_key" ON "alert_source_profiles" ("name");
-- Create index "alertsourceprofile_kind_enabled" to table: "alert_source_profiles"
CREATE INDEX "alertsourceprofile_kind_enabled" ON "alert_source_profiles" ("kind", "enabled");
-- Create index "alertsourceprofile_labels" to table: "alert_source_profiles"
CREATE INDEX "alertsourceprofile_labels" ON "alert_source_profiles" USING GIN ("labels");
